           f_temp = Math.Abs(f_temp);


           //-------------------------------------------------------------------------
           //Ток эпт  отсуствует
           //-------------------------------------------------------------------------
           Loco.temp_buffer = new byte[] { 0, 0 };
           Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 8, 2);

           //-------------------------------------------------------------------------
           //Время часы
           //-------------------------------------------------------------------------
