            {
                Loco.temp_buffer = new byte[] { 1 };
            }
            else
                Loco.temp_buffer = new byte[] { 0 };
            Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 38, 1);
            //---------------------------------------------------------------
