            else
                Loco.temp_buffer = new byte[] { 0 };
            Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 54, 1);
            //---------------------------------------------------------------
            //Лампа СОТ   ZTE
            Loco.temp_buffer = Loco.read_bytes((Int32)Loco.BA + 0x0145FFFD, 1);//читаем СОТ   ZTE
            b_temp1 = Loco.temp_buffer[0];
            if (b_temp1 != 0)
