            else
                Loco.temp_buffer = new byte[] { 0 };
            Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 55, 1);
            //---------------------------------------------------------------
            //Лампа СОТx  ZTE
            Loco.temp_buffer = Loco.read_bytes((Int32)Loco.BA + 0x0145FFFE, 1);//читаем СОТx  ZTE
            b_temp1 = Loco.temp_buffer[0];
