            else
                Loco.temp_buffer = new byte[] { 0 };
            Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 56, 1);
            //---------------------------------------------------------------
            //Лампа Тяга  ZTE
            //Loco.temp_buffer = Loco.read_bytes((Int32)Loco.BA + 0x0145FFFE, 1);//читаем Тяга  ZTE
            b_temp1 = Loco.temp_buffer[0];
