           Array.Copy(Loco.temp_buffer, 0, Loco.out_buffer, 4, 1);

           //бдительность
           Loco.temp_buffer = Loco.read_bytes((Int32)Loco.BA + 0x0032CBC0, 1);
           Loco.i_bdit_current = Loco.temp_buffer[0];

           //скор тек 2
