                //-----------------------------------------------------------------------------------
                // Функция пишет в память игры параметры neshtatki
                //-----------------------------------------------------------------------------------
                public static void write_neshtatki()
           {
               byte[] b;
               Int32 i32;
               int j = 0;

               if (i_process_name == 6)
               {
                   j = 0x54;
                   //пишем нештатки
                   for (int i = 0; i < 72; i++)//нештатки пока до 72, буфер на 100, а там посмотрим
                   {
                       if (LocoButtons.b_neshtatki[i] != 255)
                       {
                           b = Loco.read_bytes((Int32)Loco.BA + 0x8BEB4C0, 4);
                           i32 = BitConverter.ToInt32(b, 0) + j;
                           if (LocoButtons.b_neshtatki[i] == 1)
                           {
                               write_bytes(i32, b_write_1byte_1);
                               if (Form1.i_sound_peredacha == 1 && Neshtatki_flag_key_buffer[0] == 0 && list_collect_sounds_zdsim_neshtatki[i] != b_write_1byte_0)
                               {
                                   //
                                   Neshtatki_flag_key_buffer[i] = 1;
                               }
                           }
                           else
                           {
                               write_bytes(i32, b_write_1byte_0);
                               Neshtatki_flag_key_buffer[i] = 0;
                           }
                       }
                       for (int i2 = 0; i2 < 0x54; i2++)
                       {
                           j++;
                       }
                   }
               }
           }

